import React, { useEffect, useRef } from 'react';
import './Services.css';

const SERVICES = [
  { n: '01', name: 'YouTube Video Editing',          tags: ['Long-form', 'Shorts', 'Thumbnails'], price: 'From ₹4,000' },
  { n: '02', name: 'Color Grading & LUTs',           tags: ['DaVinci', 'Cinema Look'],            price: 'From ₹2,500' },
  { n: '03', name: 'Motion Graphics',                tags: ['Titles', 'Lower Thirds', 'Intros'],  price: 'From ₹3,000' },
  { n: '04', name: 'Brand & Commercial Films',       tags: ['Ads', 'Reels', 'Social Media'],      price: 'From ₹8,000' },
  { n: '05', name: 'Full Post-Production Package',   tags: ['Edit', 'Grade', 'Sound', 'Delivery'],price: 'Custom Quote' },
];

export default function Services() {
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) ref.current.querySelectorAll('.reveal').forEach(r => r.classList.add('visible'));
    }, { threshold: 0.1 });
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  return (
    <section className="section" id="services" ref={ref}>
      <p className="sec-tag reveal">05 — Services</p>
      <h2 className="sec-title reveal">What I Offer</h2>
      <div className="svc-list reveal">
        {SERVICES.map(s => (
          <div className="svc-row" key={s.n}>
            <span className="svc-num">{s.n}</span>
            <span className="svc-name">{s.name}</span>
            <div className="svc-tags">
              {s.tags.map(t => <span className="svc-tag" key={t}>{t}</span>)}
            </div>
            <span className="svc-price">{s.price}</span>
            <span className="svc-arrow">→</span>
          </div>
        ))}
      </div>
    </section>
  );
}
